#' Classify sentiment of text
#'
#' Compares the number of positive and negative words and determines
#' whether the overall sentiment is positive, negative, or neutral.
#'
#' @param counts A list containing positive and negative word counts
#' generated by sentiment_counts()
#'
#' @return A list containing positive count, negative count, and
#' the final sentiment classification (positive/negative/neutral)
#'
#' @examples
#' \dontrun{
#' counts <- sentiment_counts(string_vector)
#' sentiment_results(counts)
#' }

sentiment_results<-function(counts) {
  #call the positive and negative counts
  positive <- counts$positive
  negative <- counts$negative
  #compare number of negative and positive words to get a final output
  sentiment <- if (positive > negative) {
    "This text is positive :)"
  } else if (negative > positive) {
    "This text is negative :("
  } else {
    "This text is neutral :I"
  }

  cat("Positive word count:", positive, "\n")
  cat("Negative word count:", negative, "\n")

  return(sentiment)
}
